import { useState, useTransition } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Patient, UpdatePatientMedicalInfoInput, EmergencyContact, BLOOD_TYPES } from '@/types/medical-records';
import { updatePatientMedicalInfo } from '@/actions/medical-records';
import { toast } from 'sonner';
import {
    User,
    Phone,
    Mail,
    CreditCard,
    Calendar,
    Droplets,
    AlertTriangle,
    Heart,
    Pill,
    UserCheck,
    Edit2,
    Save,
    X,
    Stethoscope,
    Loader2
} from 'lucide-react';
import { format, differenceInYears, parseISO } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface PatientInfoTabProps {
    patient: Patient;
    onNewRecord?: () => void;
    // onUpdate prop might not be needed if we rely on router refresh or parent refetch, but let's keep it optional
    onUpdate?: () => void;
}

export function PatientInfoTab({ patient, onNewRecord, onUpdate }: PatientInfoTabProps) {
    const [isPending, startTransition] = useTransition();
    const [isEditing, setIsEditing] = useState(false);

    // Estados de edição (inicializados com dados do paciente)
    const [birthDate, setBirthDate] = useState(patient.birth_date || '');
    const [bloodType, setBloodType] = useState(patient.blood_type || '');
    const [allergies, setAllergies] = useState<string[]>(patient.allergies || []);
    const [chronicConditions, setChronicConditions] = useState<string[]>(patient.chronic_conditions || []);
    const [currentMedications, setCurrentMedications] = useState<string[]>(patient.current_medications || []);
    const [emergencyContact, setEmergencyContact] = useState<EmergencyContact>(
        patient.emergency_contact || { name: '', phone: '', relationship: '' }
    );

    // Estados para inputs temporários
    const [newAllergy, setNewAllergy] = useState('');
    const [newCondition, setNewCondition] = useState('');
    const [newMedication, setNewMedication] = useState('');

    const calculateAge = (dateString: string | null | undefined): number | null => {
        if (!dateString) return null;
        try {
            return differenceInYears(new Date(), parseISO(dateString));
        } catch {
            return null;
        }
    };

    const handleSave = () => {
        const updates: UpdatePatientMedicalInfoInput = {
            birth_date: birthDate || undefined,
            blood_type: bloodType || undefined,
            allergies,
            chronic_conditions: chronicConditions,
            current_medications: currentMedications,
            emergency_contact: emergencyContact.name ? emergencyContact : undefined,
        };

        startTransition(async () => {
            try {
                await updatePatientMedicalInfo(patient.id, updates);
                toast.success('Informações atualizadas com sucesso');
                setIsEditing(false);
                if (onUpdate) onUpdate();
            } catch (error) {
                console.error(error);
                toast.error('Erro ao atualizar informações');
            }
        });
    };

    const handleCancel = () => {
        setBirthDate(patient.birth_date || '');
        setBloodType(patient.blood_type || '');
        setAllergies(patient.allergies || []);
        setChronicConditions(patient.chronic_conditions || []);
        setCurrentMedications(patient.current_medications || []);
        setEmergencyContact(patient.emergency_contact || { name: '', phone: '', relationship: '' });
        setIsEditing(false);
    };

    const addTag = (
        value: string,
        setValue: React.Dispatch<React.SetStateAction<string>>,
        list: string[],
        setList: React.Dispatch<React.SetStateAction<string[]>>
    ) => {
        if (value.trim() && !list.includes(value.trim())) {
            setList([...list, value.trim()]);
            setValue('');
        }
    };

    const removeTag = (
        index: number,
        list: string[],
        setList: React.Dispatch<React.SetStateAction<string[]>>
    ) => {
        setList(list.filter((_, i) => i !== index));
    };

    const age = calculateAge(birthDate || patient.birth_date);

    return (
        <div className="space-y-6">
            {/* Header com botões */}
            <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold">Ficha do Paciente</h3>
                <div className="flex gap-2">
                    {onNewRecord && (
                        <Button onClick={onNewRecord} className="gap-2">
                            <Stethoscope className="h-4 w-4" />
                            Novo Atendimento
                        </Button>
                    )}
                    {!isEditing ? (
                        <Button variant="outline" size="sm" onClick={() => setIsEditing(true)} className="gap-2">
                            <Edit2 className="h-4 w-4" />
                            Editar Ficha
                        </Button>
                    ) : (
                        <>
                            <Button variant="outline" size="sm" onClick={handleCancel} className="gap-2">
                                <X className="h-4 w-4" />
                                Cancelar
                            </Button>
                            <Button size="sm" onClick={handleSave} disabled={isPending} className="gap-2">
                                {isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                                Salvar
                            </Button>
                        </>
                    )}
                </div>
            </div>

            {/* Dados Pessoais */}
            <Card>
                <CardHeader className="pb-3">
                    <CardTitle className="text-base flex items-center gap-2">
                        <User className="h-4 w-4 text-primary" />
                        Dados Pessoais
                    </CardTitle>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    <div className="space-y-1">
                        <Label className="text-muted-foreground text-xs">Nome Completo</Label>
                        <p className="font-medium">{patient.full_name}</p>
                    </div>

                    <div className="space-y-1">
                        <Label className="text-muted-foreground text-xs">CPF</Label>
                        <p className="font-medium flex items-center gap-2">
                            <CreditCard className="h-4 w-4 text-muted-foreground" />
                            {patient.cpf || 'Não informado'}
                        </p>
                    </div>

                    <div className="space-y-1">
                        <Label className="text-muted-foreground text-xs">Telefone</Label>
                        <p className="font-medium flex items-center gap-2">
                            <Phone className="h-4 w-4 text-muted-foreground" />
                            {patient.phone || 'Não informado'}
                        </p>
                    </div>

                    <div className="space-y-1">
                        <Label className="text-muted-foreground text-xs">E-mail</Label>
                        <p className="font-medium flex items-center gap-2">
                            <Mail className="h-4 w-4 text-muted-foreground" />
                            {patient.email || 'Não informado'}
                        </p>
                    </div>

                    <div className="space-y-1">
                        <Label className="text-muted-foreground text-xs">Data de Nascimento</Label>
                        {isEditing ? (
                            <Input
                                type="date"
                                value={birthDate}
                                onChange={(e) => setBirthDate(e.target.value)}
                            />
                        ) : (
                            <p className="font-medium flex items-center gap-2">
                                <Calendar className="h-4 w-4 text-muted-foreground" />
                                {(() => {
                                    try {
                                        // Use birthDate state or prop, ensuring it's not null for display if we have it
                                        const dateVal = birthDate || patient.birth_date;
                                        if (!dateVal) return 'Não informado';
                                        const date = parseISO(dateVal);
                                        if (isNaN(date.getTime()) || date.getFullYear() > 2500) return 'Data inválida';
                                        return `${format(date, 'dd/MM/yyyy', { locale: ptBR })} (${age !== null ? age : '?'} anos)`;
                                    } catch (e) {
                                        return 'Data inválida';
                                    }
                                })()}
                            </p>
                        )}
                    </div>

                    <div className="space-y-1">
                        <Label className="text-muted-foreground text-xs">Tipo Sanguíneo</Label>
                        {isEditing ? (
                            <Select value={bloodType} onValueChange={setBloodType}>
                                <SelectTrigger>
                                    <SelectValue placeholder="Selecione" />
                                </SelectTrigger>
                                <SelectContent>
                                    {BLOOD_TYPES.map((type) => (
                                        <SelectItem key={type} value={type}>
                                            {type}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        ) : (
                            <p className="font-medium flex items-center gap-2">
                                <Droplets className="h-4 w-4 text-red-500" />
                                {bloodType || 'Não informado'}
                            </p>
                        )}
                    </div>
                </CardContent>
            </Card>

            {/* Alergias */}
            <Card>
                <CardHeader className="pb-3">
                    <CardTitle className="text-base flex items-center gap-2">
                        <AlertTriangle className="h-4 w-4 text-yellow-500" />
                        Alergias
                    </CardTitle>
                    <CardDescription>Registre todas as alergias conhecidas do paciente</CardDescription>
                </CardHeader>
                <CardContent>
                    {isEditing ? (
                        <div className="space-y-3">
                            <div className="flex gap-2">
                                <Input
                                    placeholder="Digite uma alergia e pressione Enter"
                                    value={newAllergy}
                                    onChange={(e) => setNewAllergy(e.target.value)}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter') {
                                            e.preventDefault();
                                            addTag(newAllergy, setNewAllergy, allergies, setAllergies);
                                        }
                                    }}
                                />
                                <Button
                                    type="button"
                                    variant="outline"
                                    onClick={() => addTag(newAllergy, setNewAllergy, allergies, setAllergies)}
                                >
                                    Adicionar
                                </Button>
                            </div>
                            <div className="flex flex-wrap gap-2">
                                {allergies.map((allergy, index) => (
                                    <Badge
                                        key={index}
                                        variant="secondary"
                                        className="bg-yellow-100 text-yellow-800 border-yellow-300 gap-1"
                                    >
                                        {allergy}
                                        <button
                                            type="button"
                                            onClick={() => removeTag(index, allergies, setAllergies)}
                                            className="ml-1 hover:text-red-600"
                                        >
                                            ×
                                        </button>
                                    </Badge>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div className="flex flex-wrap gap-2">
                            {allergies.length > 0 ? (
                                allergies.map((allergy, index) => (
                                    <Badge
                                        key={index}
                                        variant="secondary"
                                        className="bg-yellow-100 text-yellow-800 border-yellow-300"
                                    >
                                        {allergy}
                                    </Badge>
                                ))
                            ) : (
                                <p className="text-muted-foreground text-sm">Nenhuma alergia registrada</p>
                            )}
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Condições e Medicamentos */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-base flex items-center gap-2"><Heart className="h-4 w-4 text-red-500" /> Condições Crônicas</CardTitle>
                    </CardHeader>
                    <CardContent>
                        {isEditing ? (
                            <div className="space-y-3">
                                <div className="flex gap-2">
                                    <Input value={newCondition} onChange={e => setNewCondition(e.target.value)} onKeyDown={e => e.key === 'Enter' && addTag(newCondition, setNewCondition, chronicConditions, setChronicConditions)} placeholder="Nova condição" />
                                    <Button type="button" variant="outline" onClick={() => addTag(newCondition, setNewCondition, chronicConditions, setChronicConditions)}>Add</Button>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    {chronicConditions.map((c, i) => <Badge key={i} variant="secondary" className="bg-red-100 text-red-800">{c} <span className="cursor-pointer ml-1" onClick={() => removeTag(i, chronicConditions, setChronicConditions)}>x</span></Badge>)}
                                </div>
                            </div>
                        ) : (
                            <div className="flex flex-wrap gap-2">
                                {chronicConditions.length ? chronicConditions.map((c, i) => <Badge key={i} variant="secondary" className="bg-red-100 text-red-800">{c}</Badge>) : <span className="text-sm text-muted-foreground">Nenhuma</span>}
                            </div>
                        )}
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-base flex items-center gap-2"><Pill className="h-4 w-4 text-blue-500" /> Medicamentos</CardTitle>
                    </CardHeader>
                    <CardContent>
                        {isEditing ? (
                            <div className="space-y-3">
                                <div className="flex gap-2">
                                    <Input value={newMedication} onChange={e => setNewMedication(e.target.value)} onKeyDown={e => e.key === 'Enter' && addTag(newMedication, setNewMedication, currentMedications, setCurrentMedications)} placeholder="Novo medicamento" />
                                    <Button type="button" variant="outline" onClick={() => addTag(newMedication, setNewMedication, currentMedications, setCurrentMedications)}>Add</Button>
                                </div>
                                <div className="flex flex-wrap gap-2">
                                    {currentMedications.map((m, i) => <Badge key={i} variant="secondary" className="bg-blue-100 text-blue-800">{m} <span className="cursor-pointer ml-1" onClick={() => removeTag(i, currentMedications, setCurrentMedications)}>x</span></Badge>)}
                                </div>
                            </div>
                        ) : (
                            <div className="flex flex-wrap gap-2">
                                {currentMedications.length ? currentMedications.map((m, i) => <Badge key={i} variant="secondary" className="bg-blue-100 text-blue-800">{m}</Badge>) : <span className="text-sm text-muted-foreground">Nenhum</span>}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>

            {/* Contato de Emergência */}
            <Card>
                <CardHeader className="pb-3">
                    <CardTitle className="text-base flex items-center gap-2">
                        <UserCheck className="h-4 w-4 text-green-500" />
                        Contato de Emergência
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    {isEditing ? (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="space-y-2">
                                <Label>Nome</Label>
                                <Input
                                    placeholder="Nome do contato"
                                    value={emergencyContact.name}
                                    onChange={(e) =>
                                        setEmergencyContact({ ...emergencyContact, name: e.target.value })
                                    }
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Telefone</Label>
                                <Input
                                    placeholder="(00) 00000-0000"
                                    value={emergencyContact.phone}
                                    onChange={(e) =>
                                        setEmergencyContact({ ...emergencyContact, phone: e.target.value })
                                    }
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Parentesco</Label>
                                <Input
                                    placeholder="Ex: Mãe, Cônjuge"
                                    value={emergencyContact.relationship}
                                    onChange={(e) =>
                                        setEmergencyContact({ ...emergencyContact, relationship: e.target.value })
                                    }
                                />
                            </div>
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="space-y-1">
                                <Label className="text-muted-foreground text-xs">Nome</Label>
                                <p className="font-medium">{emergencyContact.name || 'Não informado'}</p>
                            </div>
                            <div className="space-y-1">
                                <Label className="text-muted-foreground text-xs">Telefone</Label>
                                <p className="font-medium">{emergencyContact.phone || 'Não informado'}</p>
                            </div>
                            <div className="space-y-1">
                                <Label className="text-muted-foreground text-xs">Parentesco</Label>
                                <p className="font-medium">{emergencyContact.relationship || 'Não informado'}</p>
                            </div>
                        </div>
                    )}
                </CardContent>
            </Card>

        </div>
    );
}
