// Types for Medical Records System

import { Tables, TablesInsert, TablesUpdate } from '@/lib/supabase/types';
import { CRMContact } from "./crm";

// =====================================================
// BASE TYPES FROM SUPABASE
// =====================================================

export type MedicalRecord = Tables<'medical_records'>;
export type MedicalRecordInsert = TablesInsert<'medical_records'>;
export type MedicalRecordUpdate = TablesUpdate<'medical_records'>;

// =====================================================
// VITAL SIGNS
// =====================================================

export interface VitalSigns {
    bp_systolic?: number;      // Pressão sistólica (mmHg)
    bp_diastolic?: number;     // Pressão diastólica (mmHg)
    heart_rate?: number;       // Frequência cardíaca (bpm)
    respiratory_rate?: number; // Frequência respiratória (irpm)
    temperature?: number;      // Temperatura (°C)
    spo2?: number;             // Saturação de O2 (%)
    weight?: number;           // Peso (kg)
    height?: number;           // Altura (cm)
    bmi?: number;              // IMC (calculated automatically)
}

// Validation ranges for vital signs
export const VITAL_SIGNS_RANGES = {
    temperature: { min: 35, max: 42, unit: '°C' },
    bp_systolic: { min: 60, max: 250, unit: 'mmHg' },
    bp_diastolic: { min: 40, max: 150, unit: 'mmHg' },
    heart_rate: { min: 30, max: 250, unit: 'bpm' },
    respiratory_rate: { min: 8, max: 60, unit: 'irpm' },
    spo2: { min: 50, max: 100, unit: '%' },
    weight: { min: 1, max: 300, unit: 'kg' },
    height: { min: 30, max: 250, unit: 'cm' },
} as const;

// Function to calculate BMI
export function calculateBMI(weight?: number, height?: number): number | undefined {
    if (!weight || !height || height <= 0) return undefined;
    const heightInMeters = height / 100;
    return Number((weight / (heightInMeters * heightInMeters)).toFixed(2));
}

// =====================================================
// MEDICATION PRESCRIPTION
// =====================================================

export interface MedicationPrescription {
    id?: string;
    medication: string;        // Medication name
    dosage: string;            // Dosage (e.g., "500mg")
    frequency: string;         // Frequency (e.g., "8/8h")
    duration: string;          // Duration (e.g., "7 days")
    quantity?: string;         // Quantity (e.g., "21 tablets")
    instructions?: string;     // Additional instructions
    route?: string;            // Administration route (oral, IV, IM, etc.)
}

// =====================================================
// REQUESTED EXAM
// =====================================================

export interface RequestedExam {
    id?: string;
    exam_name: string;         // Exam name
    urgency?: 'routine' | 'urgent' | 'emergency';
    notes?: string;            // Observations
    category?: string;         // Category (lab, imaging, etc.)
}

// =====================================================
// EMERGENCY CONTACT
// =====================================================

export interface EmergencyContact {
    name: string;
    phone: string;
    relationship: string;      // Relationship
}

// =====================================================
// MEDICAL RECORD WITH RELATIONS
// =====================================================

export interface MedicalRecordWithRelations extends MedicalRecord {
    contact?: CRMContact;
    doctor?: {
        id: string;
        full_name: string;
        email?: string;
    };
}

// =====================================================
// PRESCRIPTION (PRINTABLE)
// =====================================================

export interface Prescription {
    id: string;
    medical_record_id?: string | null;
    contact_id: string;
    doctor_id: string;

    medications: MedicationPrescription[];
    notes?: string | null;
    prescription_date: string;
    valid_until?: string | null;
    prescription_type: 'simple' | 'controlled' | 'special';

    is_printed: boolean;
    printed_at?: string | null;

    created_at: string;
    updated_at: string;

    // Relations
    contact?: CRMContact;
    doctor?: {
        id: string;
        full_name: string;
        email?: string;
    };
}

// =====================================================
// PATIENT (CONTACT EXTENSION)
// =====================================================

export interface Patient extends CRMContact {
    // Additional medical-specific fields not in CRMContact base
    blood_type?: string | null;
    insurance_type?: 'convenio' | 'particular' | null;
    insurance_name?: string | null;
    cpf?: string | null;
    allergies?: string[] | null;
    chronic_conditions?: string[] | null;
    current_medications?: string[] | null;
    emergency_contact?: EmergencyContact | null;

    // Computed fields
    total_appointments?: number;
    last_appointment?: string | null;
    total_records?: number;
}

// =====================================================
// FORMS (INPUTS)
// =====================================================

export interface CreateMedicalRecordInput {
    contact_id: string;
    appointment_id?: string;

    // Anamnesis
    chief_complaint?: string;
    history_present_illness?: string;
    past_medical_history?: string;
    family_history?: string;
    social_history?: string;

    // Physical Exam
    review_of_systems?: Record<string, unknown>;
    physical_exam?: Record<string, unknown>;

    // Diagnosis
    diagnosis?: string;

    // Conduct
    treatment_plan?: string;
    follow_up_instructions?: string;

    // Prescriptions
    medications?: MedicationPrescription[];

    // Treatment flag
    is_in_treatment?: boolean;

    // Additional fields used by NewRecordModal
    vital_signs?: VitalSigns;
    allergies_noted?: string[];
    cid_codes?: string[];
    prescriptions?: MedicationPrescription[];
    exams_requested?: RequestedExam[];
}

export interface UpdatePatientMedicalInfoInput {
    birth_date?: string;
    blood_type?: string;
    allergies?: string[];
    chronic_conditions?: string[];
    current_medications?: string[];
    emergency_contact?: EmergencyContact;
}

export interface CreatePrescriptionInput {
    contact_id: string;
    medical_record_id?: string;
    medications: MedicationPrescription[];
    notes?: string;
    valid_until?: string;
    prescription_type?: 'simple' | 'controlled' | 'special';
}

