import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { CRMContact } from "@/types/crm";
import { useState, useMemo } from "react";
import { Search, User } from "lucide-react";

interface PatientSelectorModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSelect: (patient: CRMContact) => void;
    patients: CRMContact[];
}

export function PatientSelectorModal({ open, onOpenChange, onSelect, patients }: PatientSelectorModalProps) {
    const [searchTerm, setSearchTerm] = useState("");

    const filtered = useMemo(() => {
        if (!searchTerm) return patients;
        const term = searchTerm.toLowerCase();
        return patients.filter(p => p.full_name?.toLowerCase().includes(term));
    }, [patients, searchTerm]);

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent>
                <DialogHeader>
                    <DialogTitle>Selecionar Paciente</DialogTitle>
                </DialogHeader>
                <div className="space-y-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar paciente..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            className="pl-9"
                        />
                    </div>
                    <ScrollArea className="h-[300px]">
                        {filtered.map(p => (
                            <button
                                key={p.id}
                                onClick={() => onSelect(p)}
                                className="w-full text-left p-3 hover:bg-muted rounded-md flex items-center gap-3"
                            >
                                <User className="h-5 w-5 text-muted-foreground" />
                                <span className="font-medium">{p.full_name}</span>
                            </button>
                        ))}
                    </ScrollArea>
                </div>
            </DialogContent>
        </Dialog>
    )
}
