import { useState, useTransition } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { ScrollArea } from '@/components/ui/scroll-area';
import { calculateBMI } from '@/types/medical-records'; // Assuming helper function is exported, or I need to recreate it
import { createMedicalRecord } from '@/actions/medical-records';
import { toast } from 'sonner';
import {
    CreateMedicalRecordInput,
    MedicationPrescription,
    RequestedExam,
    VitalSigns,
    RECORD_TYPES,
    COMMON_CID_CODES,
    MEDICATION_ROUTES,
    UpdatePatientMedicalInfoInput
} from '@/types/medical-records';
import { CRMContact } from '@/types/crm';
import {
    Stethoscope,
    Heart,
    Thermometer,
    Activity,
    Scale,
    Ruler,
    Pill,
    TestTube,
    FileText,
    Save,
    X,
    Plus,
    Trash2,
    Search,
    Loader2
} from 'lucide-react';
import { DatePicker } from "@/components/ui/date-picker"; // Ensure this component exists or use input type="date"
import { format } from "date-fns";

// Helper for BMI classification
const classifyBMI = (bmi?: number) => {
    if (!bmi) return { label: '', color: '' };
    if (bmi < 18.5) return { label: 'Abaixo do peso', color: 'yellow' };
    if (bmi < 25) return { label: 'Peso normal', color: 'green' };
    if (bmi < 30) return { label: 'Sobrepeso', color: 'orange' };
    if (bmi < 35) return { label: 'Obesidade Grau I', color: 'red' };
    if (bmi < 40) return { label: 'Obesidade Grau II', color: 'red' };
    return { label: 'Obesidade Grau III', color: 'red' };
};

// Schema de validação
const recordSchema = z.object({
    record_type: z.enum(['consultation', 'return', 'procedure', 'exam', 'emergency']),
    chief_complaint: z.string().optional(),
    history_current_illness: z.string().optional(),
    past_medical_history: z.string().optional(),
    family_history: z.string().optional(),
    social_history: z.string().optional(),
    general_condition: z.string().optional(),
    physical_exam_notes: z.string().optional(),
    diagnostic_hypothesis: z.string().optional(),
    treatment_plan: z.string().optional(),
    complications: z.string().optional(),
    patient_instructions: z.string().optional(),
    follow_up_notes: z.string().optional(),
    next_appointment_date: z.string().optional(),
});

type RecordFormData = z.infer<typeof recordSchema>;

interface NewRecordModalProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    patient: CRMContact;
    onSuccess?: () => void;
}

export function NewRecordModal({ open, onOpenChange, patient, onSuccess }: NewRecordModalProps) {
    const [isPending, startTransition] = useTransition();
    const [activeTab, setActiveTab] = useState('anamnese');

    // Estados para sinais vitais
    const [vitalSigns, setVitalSigns] = useState<VitalSigns>({});

    // Estados para listas
    const [allergiesNoted, setAllergiesNoted] = useState<string[]>([]);
    const [cidCodes, setCidCodes] = useState<string[]>([]);
    const [prescriptions, setPrescriptions] = useState<MedicationPrescription[]>([]);
    const [examsRequested, setExamsRequested] = useState<RequestedExam[]>([]);

    // Estados para inputs temporários
    const [newAllergy, setNewAllergy] = useState('');
    const [cidSearch, setCidSearch] = useState('');
    const [newMedication, setNewMedication] = useState<Partial<MedicationPrescription>>({});
    const [newExam, setNewExam] = useState<Partial<RequestedExam>>({});

    const form = useForm<RecordFormData>({
        resolver: zodResolver(recordSchema),
        defaultValues: {
            record_type: 'consultation',
        },
    });

    // Calcular IMC automaticamente
    const bmi = calculateBMI(vitalSigns.weight, vitalSigns.height);
    const bmiClassification = classifyBMI(bmi);

    // Filtrar CIDs pela busca
    const filteredCIDs = cidSearch
        ? COMMON_CID_CODES.filter(
            cid =>
                cid.code.toLowerCase().includes(cidSearch.toLowerCase()) ||
                cid.description.toLowerCase().includes(cidSearch.toLowerCase())
        )
        : COMMON_CID_CODES;

    const handleSubmit = async (data: RecordFormData) => {
        const recordInput: CreateMedicalRecordInput = {
            contact_id: patient.id,
            ...data,
            vital_signs: Object.keys(vitalSigns).length > 0 ? { ...vitalSigns, bmi: bmi || undefined } : undefined,
            allergies_noted: allergiesNoted.length > 0 ? allergiesNoted : undefined,
            cid_codes: cidCodes.length > 0 ? cidCodes : undefined,
            prescriptions: prescriptions.length > 0 ? prescriptions : undefined,
            exams_requested: examsRequested.length > 0 ? examsRequested : undefined,
        };

        startTransition(async () => {
            try {
                await createMedicalRecord(recordInput);
                toast.success('Prontuário salvo com sucesso');
                onOpenChange(false);
                resetForm();
                if (onSuccess) onSuccess();
            } catch (error) {
                console.error('Erro ao criar prontuário:', error);
                toast.error('Erro ao salvar prontuário');
            }
        });
    };

    const resetForm = () => {
        form.reset();
        setVitalSigns({});
        setAllergiesNoted([]);
        setCidCodes([]);
        setPrescriptions([]);
        setExamsRequested([]);
        setActiveTab('anamnese');
    };

    const addPrescription = () => {
        if (newMedication.medication && newMedication.dosage) {
            setPrescriptions([...prescriptions, {
                id: crypto.randomUUID(),
                medication: newMedication.medication!,
                dosage: newMedication.dosage!,
                frequency: newMedication.frequency || '',
                duration: newMedication.duration || '',
                quantity: newMedication.quantity,
                instructions: newMedication.instructions,
                route: newMedication.route,
            } as MedicationPrescription]);
            setNewMedication({});
        } else {
            toast.warning('Preencha pelo menos o nome e dosagem');
        }
    };

    const removePrescription = (index: number) => {
        setPrescriptions(prescriptions.filter((_, i) => i !== index));
    };

    const addExam = () => {
        if (newExam.exam_name) {
            setExamsRequested([...examsRequested, {
                id: crypto.randomUUID(),
                exam_name: newExam.exam_name!,
                urgency: newExam.urgency || 'routine',
                notes: newExam.notes,
            } as RequestedExam]);
            setNewExam({});
        } else {
            toast.warning('Preencha o nome do exame');
        }
    };

    const removeExam = (index: number) => {
        setExamsRequested(examsRequested.filter((_, i) => i !== index));
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-4xl max-h-[90vh] p-0 flex flex-col">
                <DialogHeader className="p-6 pb-0 shrink-0">
                    <DialogTitle className="flex items-center gap-2">
                        <Stethoscope className="h-5 w-5 text-primary" />
                        Novo Atendimento
                    </DialogTitle>
                    <DialogDescription>
                        Paciente: <strong>{patient.full_name}</strong>
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={form.handleSubmit(handleSubmit)} className="flex-1 flex flex-col overflow-hidden">
                    <ScrollArea className="flex-1">
                        <div className="p-6 pt-4">
                            {/* Tipo de atendimento */}
                            <div className="mb-4">
                                <Label>Tipo de Atendimento</Label>
                                <Select
                                    value={form.watch('record_type')}
                                    onValueChange={(value: any) => form.setValue('record_type', value)}
                                >
                                    <SelectTrigger className="w-full md:w-[300px]">
                                        <SelectValue />
                                    </SelectTrigger>
                                    <SelectContent>
                                        {RECORD_TYPES.map((type) => (
                                            <SelectItem key={type.value} value={type.value}>
                                                {type.label} - {type.description}
                                            </SelectItem>
                                        ))}
                                    </SelectContent>
                                </Select>
                            </div>

                            <Tabs value={activeTab} onValueChange={setActiveTab}>
                                <TabsList className="grid grid-cols-5 w-full">
                                    <TabsTrigger value="anamnese">Anamnese</TabsTrigger>
                                    <TabsTrigger value="exame">Exame Físico</TabsTrigger>
                                    <TabsTrigger value="diagnostico">Diagnóstico</TabsTrigger>
                                    <TabsTrigger value="prescricao">Prescrições</TabsTrigger>
                                    <TabsTrigger value="exames">Exames</TabsTrigger>
                                </TabsList>

                                {/* Tab Anamnese */}
                                <TabsContent value="anamnese" className="space-y-4 mt-4 text-left">
                                    <div className="space-y-2">
                                        <Label htmlFor="chief_complaint">Queixa Principal</Label>
                                        <Textarea
                                            id="chief_complaint"
                                            placeholder="Qual o motivo da consulta?"
                                            {...form.register('chief_complaint')}
                                            rows={2}
                                        />
                                    </div>

                                    <div className="space-y-2">
                                        <Label htmlFor="history_current_illness">História da Doença Atual (HDA)</Label>
                                        <Textarea
                                            id="history_current_illness"
                                            placeholder="Descreva a evolução dos sintomas..."
                                            {...form.register('history_current_illness')}
                                            rows={4}
                                        />
                                    </div>

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label htmlFor="past_medical_history">História Patológica Pregressa</Label>
                                            <Textarea
                                                id="past_medical_history"
                                                placeholder="Doenças anteriores, cirurgias..."
                                                {...form.register('past_medical_history')}
                                                rows={3}
                                            />
                                        </div>

                                        <div className="space-y-2">
                                            <Label htmlFor="family_history">História Familiar</Label>
                                            <Textarea
                                                id="family_history"
                                                placeholder="Doenças na família..."
                                                {...form.register('family_history')}
                                                rows={3}
                                            />
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <Label htmlFor="social_history">Hábitos de Vida</Label>
                                        <Textarea
                                            id="social_history"
                                            placeholder="Tabagismo, etilismo, atividade física, alimentação..."
                                            {...form.register('social_history')}
                                            rows={2}
                                        />
                                    </div>

                                    {/* Alergias identificadas nesta consulta */}
                                    <div className="space-y-2">
                                        <Label>Alergias Identificadas nesta Consulta</Label>
                                        <div className="flex gap-2">
                                            <Input
                                                placeholder="Adicionar alergia..."
                                                value={newAllergy}
                                                onChange={(e) => setNewAllergy(e.target.value)}
                                                onKeyDown={(e) => {
                                                    if (e.key === 'Enter') {
                                                        e.preventDefault();
                                                        if (newAllergy.trim()) {
                                                            setAllergiesNoted([...allergiesNoted, newAllergy.trim()]);
                                                            setNewAllergy('');
                                                        }
                                                    }
                                                }}
                                            />
                                            <Button
                                                type="button"
                                                variant="outline"
                                                onClick={() => {
                                                    if (newAllergy.trim()) {
                                                        setAllergiesNoted([...allergiesNoted, newAllergy.trim()]);
                                                        setNewAllergy('');
                                                    }
                                                }}
                                            >
                                                <Plus className="h-4 w-4" />
                                            </Button>
                                        </div>
                                        {allergiesNoted.length > 0 && (
                                            <div className="flex flex-wrap gap-2 mt-2">
                                                {allergiesNoted.map((allergy, index) => (
                                                    <Badge key={index} variant="secondary" className="gap-1">
                                                        {allergy}
                                                        <button
                                                            type="button"
                                                            onClick={() => setAllergiesNoted(allergiesNoted.filter((_, i) => i !== index))}
                                                            className="ml-1 hover:text-destructive"
                                                        >
                                                            ×
                                                        </button>
                                                    </Badge>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                </TabsContent>

                                {/* Tab Exame Físico */}
                                <TabsContent value="exame" className="space-y-4 mt-4 text-left">
                                    {/* Sinais Vitais */}
                                    <Card>
                                        <CardHeader className="pb-3">
                                            <CardTitle className="text-base flex items-center gap-2">
                                                <Activity className="h-4 w-4 text-primary" />
                                                Sinais Vitais
                                            </CardTitle>
                                        </CardHeader>
                                        <CardContent>
                                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                                <div className="space-y-2">
                                                    <Label className="flex items-center gap-1">
                                                        <Heart className="h-3 w-3 text-red-500" />
                                                        PA Sistólica
                                                    </Label>
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            type="number"
                                                            placeholder="120"
                                                            value={vitalSigns.bp_systolic || ''}
                                                            onChange={(e) => setVitalSigns({ ...vitalSigns, bp_systolic: Number(e.target.value) || undefined })}
                                                        />
                                                        <span className="text-xs text-muted-foreground">mmHg</span>
                                                    </div>
                                                </div>

                                                <div className="space-y-2">
                                                    <Label className="flex items-center gap-1">
                                                        <Heart className="h-3 w-3 text-red-500" />
                                                        PA Diastólica
                                                    </Label>
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            type="number"
                                                            placeholder="80"
                                                            value={vitalSigns.bp_diastolic || ''}
                                                            onChange={(e) => setVitalSigns({ ...vitalSigns, bp_diastolic: Number(e.target.value) || undefined })}
                                                        />
                                                        <span className="text-xs text-muted-foreground">mmHg</span>
                                                    </div>
                                                </div>

                                                <div className="space-y-2">
                                                    <Label className="flex items-center gap-1">
                                                        <Activity className="h-3 w-3 text-pink-500" />
                                                        Freq. Cardíaca
                                                    </Label>
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            type="number"
                                                            placeholder="70"
                                                            value={vitalSigns.heart_rate || ''}
                                                            onChange={(e) => setVitalSigns({ ...vitalSigns, heart_rate: Number(e.target.value) || undefined })}
                                                        />
                                                        <span className="text-xs text-muted-foreground">bpm</span>
                                                    </div>
                                                </div>

                                                <div className="space-y-2">
                                                    <Label className="flex items-center gap-1">
                                                        <Thermometer className="h-3 w-3 text-orange-500" />
                                                        Temperatura
                                                    </Label>
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            type="number"
                                                            step="0.1"
                                                            placeholder="36.5"
                                                            value={vitalSigns.temperature || ''}
                                                            onChange={(e) => setVitalSigns({ ...vitalSigns, temperature: Number(e.target.value) || undefined })}
                                                        />
                                                        <span className="text-xs text-muted-foreground">°C</span>
                                                    </div>
                                                </div>

                                                <div className="space-y-2">
                                                    <Label className="flex items-center gap-1">
                                                        <Scale className="h-3 w-3 text-green-500" />
                                                        Peso
                                                    </Label>
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            type="number"
                                                            step="0.1"
                                                            placeholder="70"
                                                            value={vitalSigns.weight || ''}
                                                            onChange={(e) => setVitalSigns({ ...vitalSigns, weight: Number(e.target.value) || undefined })}
                                                        />
                                                        <span className="text-xs text-muted-foreground">kg</span>
                                                    </div>
                                                </div>

                                                <div className="space-y-2">
                                                    <Label className="flex items-center gap-1">
                                                        <Ruler className="h-3 w-3 text-purple-500" />
                                                        Altura
                                                    </Label>
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            type="number"
                                                            placeholder="170"
                                                            value={vitalSigns.height || ''}
                                                            onChange={(e) => setVitalSigns({ ...vitalSigns, height: Number(e.target.value) || undefined })}
                                                        />
                                                        <span className="text-xs text-muted-foreground">cm</span>
                                                    </div>
                                                </div>
                                            </div>

                                            {/* IMC calculado */}
                                            {bmi && (
                                                <div className="mt-4 p-3 rounded-lg bg-muted/50">
                                                    <p className="text-sm">
                                                        <strong>IMC:</strong> {bmi} kg/m² -{' '}
                                                        <span className={`font-medium text-${bmiClassification.color}-600`}>
                                                            {bmiClassification.label}
                                                        </span>
                                                    </p>
                                                </div>
                                            )}
                                        </CardContent>
                                    </Card>

                                    {/* Estado geral e exame físico */}
                                    <div className="space-y-2">
                                        <Label htmlFor="general_condition">Estado Geral</Label>
                                        <Input
                                            id="general_condition"
                                            placeholder="Bom estado geral, lúcido, orientado..."
                                            {...form.register('general_condition')}
                                        />
                                    </div>

                                    <div className="space-y-2">
                                        <Label htmlFor="physical_exam_notes">Exame Físico Detalhado</Label>
                                        <Textarea
                                            id="physical_exam_notes"
                                            placeholder="Descreva o exame físico por sistemas (cabeça, pescoço, tórax, abdome, membros...)"
                                            {...form.register('physical_exam_notes')}
                                            rows={6}
                                        />
                                    </div>
                                </TabsContent>

                                {/* Tab Diagnóstico */}
                                <TabsContent value="diagnostico" className="space-y-4 mt-4 text-left">
                                    <div className="space-y-2">
                                        <Label htmlFor="diagnostic_hypothesis">Hipótese Diagnóstica</Label>
                                        <Textarea
                                            id="diagnostic_hypothesis"
                                            placeholder="Descreva a hipótese diagnóstica..."
                                            {...form.register('diagnostic_hypothesis')}
                                            rows={3}
                                        />
                                    </div>

                                    {/* Busca CID-10 */}
                                    <div className="space-y-2">
                                        <Label>Código CID-10</Label>
                                        <div className="relative">
                                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                            <Input
                                                placeholder="Buscar CID por código ou descrição..."
                                                value={cidSearch}
                                                onChange={(e) => setCidSearch(e.target.value)}
                                                className="pl-9"
                                            />
                                        </div>
                                        {cidSearch && (
                                            <div className="max-h-40 overflow-y-auto border rounded-md">
                                                {filteredCIDs.slice(0, 10).map((cid) => (
                                                    <button
                                                        key={cid.code}
                                                        type="button"
                                                        className="w-full p-2 text-left hover:bg-muted text-sm border-b last:border-b-0"
                                                        onClick={() => {
                                                            if (!cidCodes.includes(cid.code)) {
                                                                setCidCodes([...cidCodes, cid.code]);
                                                            }
                                                            setCidSearch('');
                                                        }}
                                                    >
                                                        <span className="font-medium">{cid.code}</span> - {cid.description}
                                                    </button>
                                                ))}
                                            </div>
                                        )}
                                        <div className="flex flex-wrap gap-2 mt-2">
                                            {cidCodes.map((code, index) => {
                                                const cidInfo = COMMON_CID_CODES.find(c => c.code === code);
                                                return (
                                                    <Badge key={index} variant="secondary" className="gap-1">
                                                        {code}
                                                        {cidInfo && <span className="text-xs opacity-70">({cidInfo.description.substring(0, 15)}...)</span>}
                                                        <button
                                                            type="button"
                                                            onClick={() => setCidCodes(cidCodes.filter((_, i) => i !== index))}
                                                            className="ml-1 hover:text-destructive"
                                                        >
                                                            ×
                                                        </button>
                                                    </Badge>
                                                )
                                            })}
                                        </div>
                                    </div>

                                    <div className="space-y-2">
                                        <Label htmlFor="treatment_plan">Conduta / Plano Terapêutico</Label>
                                        <Textarea
                                            id="treatment_plan"
                                            placeholder="Descreva o tratamento proposto..."
                                            {...form.register('treatment_plan')}
                                            rows={3}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="patient_instructions">Orientações ao Paciente</Label>
                                        <Textarea
                                            id="patient_instructions"
                                            placeholder="Orientações gerais..."
                                            {...form.register('patient_instructions')}
                                            rows={3}
                                        />
                                    </div>
                                </TabsContent>

                                {/* Tab Prescrições */}
                                <TabsContent value="prescricao" className="space-y-4 mt-4 text-left">
                                    {/* Form fields for new medication */}
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 border p-4 rounded-md">
                                        <div className="space-y-2">
                                            <Label>Medicamento *</Label>
                                            <Input placeholder="Nome" value={newMedication.medication || ''} onChange={e => setNewMedication({ ...newMedication, medication: e.target.value })} />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Dosagem *</Label>
                                            <Input placeholder="Ex: 500mg" value={newMedication.dosage || ''} onChange={e => setNewMedication({ ...newMedication, dosage: e.target.value })} />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Posologia</Label>
                                            <Input placeholder="Ex: 8/8h" value={newMedication.frequency || ''} onChange={e => setNewMedication({ ...newMedication, frequency: e.target.value })} />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Duração</Label>
                                            <Input placeholder="Ex: 7 dias" value={newMedication.duration || ''} onChange={e => setNewMedication({ ...newMedication, duration: e.target.value })} />
                                        </div>
                                        <Button type="button" onClick={addPrescription} className="col-span-2">Adicionar</Button>
                                    </div>

                                    {prescriptions.map((p, i) => (
                                        <div key={i} className="flex justify-between items-center border p-2 rounded-md bg-muted/20">
                                            <div>
                                                <span className="font-bold">{p.medication} {p.dosage}</span>
                                                <span className="text-sm ml-2 text-muted-foreground">{p.frequency} - {p.duration}</span>
                                            </div>
                                            <Button type="button" variant="ghost" size="sm" onClick={() => removePrescription(i)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                                        </div>
                                    ))}
                                </TabsContent>

                                {/* Tab Exames */}
                                <TabsContent value="exames" className="space-y-4 mt-4 text-left">
                                    <div className="flex gap-2">
                                        <Input placeholder="Nome do exame" value={newExam.exam_name || ''} onChange={e => setNewExam({ ...newExam, exam_name: e.target.value })} />
                                        <Button type="button" onClick={addExam}>Adicionar</Button>
                                    </div>
                                    {examsRequested.map((e, i) => (
                                        <div key={i} className="flex justify-between items-center border p-2 rounded-md bg-muted/20">
                                            <span>{e.exam_name}</span>
                                            <Button type="button" variant="ghost" size="sm" onClick={() => removeExam(i)}><Trash2 className="h-4 w-4 text-destructive" /></Button>
                                        </div>
                                    ))}
                                </TabsContent>

                            </Tabs>
                        </div>
                    </ScrollArea>
                    <div className="flex justify-end gap-2 p-4 border-t shrink-0">
                        <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>Cancelar</Button>
                        <Button type="submit" disabled={isPending}>{isPending ? <Loader2 className="animate-spin h-4 w-4 mr-2" /> : null} Salvar Prontuário</Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    );
}
