import { useQuery } from '@tanstack/react-query';
import { getPrescriptions } from '@/actions/medical-records';
import { CardContent } from "@/components/ui/card";
import { Loader2, Pill } from "lucide-react";

interface PrescriptionsTabProps {
    patientId: string;
}

export function PrescriptionsTab({ patientId }: PrescriptionsTabProps) {
    const { data: prescriptions = [], isLoading } = useQuery({
        queryKey: ['prescriptions', patientId],
        queryFn: () => getPrescriptions(patientId)
    });

    if (isLoading) {
        return <Loader2 className="h-8 w-8 animate-spin mx-auto mt-8" />;
    }

    if (prescriptions.length === 0) {
        return (
            <CardContent className="flex flex-col items-center justify-center p-8 text-center text-muted-foreground">
                <Pill className="h-12 w-12 mb-4 opacity-50" />
                <p>Nenhuma receita registrada.</p>
            </CardContent>
        );
    }

    return (
        <div className="space-y-4 p-4">
            {prescriptions.map((pres: any) => (
                <div key={pres.id} className="border p-4 rounded-md">
                    <div className="font-semibold">Data: {new Date(pres.created_at).toLocaleDateString()}</div>
                    <div className="mt-2 text-sm">{pres.medications?.map((m: any) => m.medication).join(', ')}</div>
                </div>
            ))}
        </div>
    );
}
