'use client'

import { useState, useMemo } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    ClipboardList,
    Search,
    User,
    Calendar,
    ChevronRight,
    AlertCircle,
    Stethoscope,
    Phone,
    CreditCard,
    Plus,
    Pill,
    History,
    Loader2
} from "lucide-react";
import { differenceInYears, parseISO } from "date-fns";
import { CRMContact } from "@/types/crm";
import { Patient } from "@/types/medical-records";
import { PatientSelectorModal } from "@/components/medical-records/PatientSelectorModal";
import { MedicalHistoryTab } from "@/components/medical-records/MedicalHistoryTab";
import { PatientInfoTab } from "@/components/medical-records/PatientInfoTab";
import { PrescriptionsTab } from "@/components/medical-records/PrescriptionsTab";
import { NewRecordModal } from "@/components/medical-records/NewRecordModal";

interface MedicalRecordsClientProps {
    initialPatients: CRMContact[];
    userId: string;
    userRole?: string;
}

export default function MedicalRecordsClient({ initialPatients, userId, userRole }: MedicalRecordsClientProps) {
    const [patients, setPatients] = useState<CRMContact[]>(initialPatients);
    const [searchTerm, setSearchTerm] = useState("");
    const [selectedPatient, setSelectedPatient] = useState<CRMContact | null>(null);
    const [activeTab, setActiveTab] = useState("ficha");

    const [isPatientSelectorOpen, setIsPatientSelectorOpen] = useState(false);
    const [isNewRecordModalOpen, setIsNewRecordModalOpen] = useState(false);

    // Filter patients
    const filteredPatients = useMemo(() => {
        if (!searchTerm) return patients;
        const term = searchTerm.toLowerCase();
        return patients.filter(
            (patient) =>
                patient.full_name?.toLowerCase().includes(term) ||
                patient.phone?.includes(term) ||
                patient.email?.toLowerCase().includes(term)
        );
    }, [patients, searchTerm]);

    const calculateAge = (dateString?: string | null) => {
        if (!dateString) return null;
        try {
            return differenceInYears(new Date(), new Date(dateString));
        } catch {
            return null;
        }
    };

    const handlePatientSelect = (patient: CRMContact) => {
        setSelectedPatient(patient);
        setActiveTab("ficha");
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
                        <ClipboardList className="h-7 w-7 text-primary" />
                        Prontuários Médicos
                    </h1>
                    <p className="text-muted-foreground">
                        Gerencie prontuários, histórico clínico e receitas dos pacientes
                    </p>
                </div>
                <Button onClick={() => setIsPatientSelectorOpen(true)} className="gap-2">
                    <Plus className="h-4 w-4" />
                    Criar Novo Prontuário
                </Button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
                {/* Patient List */}
                <Card className="lg:col-span-4 xl:col-span-3 h-[calc(100vh-200px)] flex flex-col">
                    <CardHeader className="pb-3 shrink-0">
                        <CardTitle className="text-lg flex items-center gap-2">
                            <User className="h-5 w-5 text-primary" />
                            Pacientes
                        </CardTitle>
                        <CardDescription>
                            {filteredPatients.length} paciente(s)
                        </CardDescription>
                        <div className="relative mt-2">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Buscar por nome, CPF ou telefone..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-9"
                            />
                        </div>
                    </CardHeader>
                    <CardContent className="p-0 flex-1 overflow-hidden">
                        <ScrollArea className="h-full">
                            {filteredPatients.length === 0 ? (
                                <div className="p-6 text-center text-muted-foreground">
                                    <User className="h-10 w-10 mx-auto mb-2 opacity-50" />
                                    <p className="font-medium">Nenhum paciente encontrado</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-border">
                                    {filteredPatients.map((patient) => {
                                        const isSelected = selectedPatient?.id === patient.id;
                                        const age = calculateAge(patient.birth_date || null);

                                        return (
                                            <button
                                                key={patient.id}
                                                onClick={() => handlePatientSelect(patient)}
                                                className={`w-full p-4 text-left hover:bg-muted/50 transition-colors ${isSelected ? "bg-primary/10 border-l-2 border-primary" : ""
                                                    }`}
                                            >
                                                <div className="flex items-center justify-between">
                                                    <div className="space-y-1 flex-1 min-w-0">
                                                        <p className="font-medium text-foreground truncate">
                                                            {patient.full_name}
                                                        </p>
                                                        <div className="flex items-center gap-3 text-sm text-muted-foreground">
                                                            {patient.phone && (
                                                                <span className="flex items-center gap-1">
                                                                    <Phone className="h-3 w-3" />
                                                                    {patient.phone}
                                                                </span>
                                                            )}
                                                        </div>
                                                        <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                                            {age && <span>{age} anos</span>}
                                                        </div>
                                                    </div>
                                                    <ChevronRight className={`h-5 w-5 text-muted-foreground shrink-0 transition-transform ${isSelected ? 'text-primary rotate-90' : ''}`} />
                                                </div>
                                            </button>
                                        );
                                    })}
                                </div>
                            )}
                        </ScrollArea>
                    </CardContent>
                </Card>

                {/* Patient Detail */}
                <Card className="lg:col-span-8 xl:col-span-9 flex flex-col h-[calc(100vh-200px)]">
                    {selectedPatient ? (
                        <>
                            <CardHeader className="pb-3 border-b shrink-0">
                                <div className="flex items-start justify-between">
                                    <div className="flex items-center gap-4">
                                        <div className="h-14 w-14 rounded-full bg-primary/10 flex items-center justify-center font-bold text-primary text-xl">
                                            {selectedPatient.full_name?.substring(0, 2).toUpperCase()}
                                        </div>
                                        <div>
                                            <CardTitle className="text-xl">{selectedPatient.full_name}</CardTitle>
                                            <CardDescription className="flex items-center gap-4 mt-1">
                                                {selectedPatient.phone && (
                                                    <span className="flex items-center gap-1">
                                                        <Phone className="h-4 w-4" /> {selectedPatient.phone}
                                                    </span>
                                                )}
                                                {/* Add more details here if available */}
                                            </CardDescription>
                                        </div>
                                    </div>
                                    {/* Badges/Tags here */}
                                </div>
                            </CardHeader>
                            <CardContent className="pt-4 flex-1 overflow-hidden flex flex-col">
                                <Tabs value={activeTab} onValueChange={setActiveTab} className="flex-1 flex flex-col">
                                    <TabsList className="grid grid-cols-3 w-full max-w-md shrink-0">
                                        <TabsTrigger value="ficha" className="gap-2"><User className="h-4 w-4" /> Ficha</TabsTrigger>
                                        <TabsTrigger value="historico" className="gap-2"><History className="h-4 w-4" /> Histórico</TabsTrigger>
                                        <TabsTrigger value="receitas" className="gap-2"><Pill className="h-4 w-4" /> Receitas</TabsTrigger>
                                    </TabsList>

                                    <div className="flex-1 overflow-auto mt-4">
                                        <TabsContent value="ficha" className="m-0 h-full">
                                            <PatientInfoTab patient={selectedPatient as Patient} />
                                        </TabsContent>
                                        <TabsContent value="historico" className="m-0 h-full">
                                            <MedicalHistoryTab patientId={selectedPatient.id} />
                                        </TabsContent>
                                        <TabsContent value="receitas" className="m-0 h-full">
                                            <PrescriptionsTab patientId={selectedPatient.id} />
                                        </TabsContent>
                                    </div>
                                </Tabs>
                            </CardContent>
                        </>
                    ) : (
                        <CardContent className="flex items-center justify-center h-full">
                            <div className="text-center text-muted-foreground">
                                <Stethoscope className="h-16 w-16 mx-auto mb-4 opacity-30" />
                                <h3 className="text-lg font-medium mb-2">Selecione um paciente</h3>
                                <p className="text-sm max-w-md">
                                    Escolha um paciente na lista ao lado para visualizar seu prontuário.
                                </p>
                            </div>
                        </CardContent>
                    )}
                </Card>
            </div>

            <PatientSelectorModal
                open={isPatientSelectorOpen}
                onOpenChange={setIsPatientSelectorOpen}
                onSelect={(patient) => {
                    setSelectedPatient(patient);
                    setIsPatientSelectorOpen(false);
                    setActiveTab("historico");
                    setTimeout(() => setIsNewRecordModalOpen(true), 100);
                }}
                patients={patients}
            />

            {selectedPatient && (
                <NewRecordModal
                    open={isNewRecordModalOpen}
                    onOpenChange={setIsNewRecordModalOpen}
                    patient={selectedPatient}
                    onSuccess={() => {
                        // Refresh history in tab (maybe via refetch context or simple re-mount)
                        // For now relies on tab's internal fetching
                    }}
                />
            )}
        </div>
    );
}
