import { useState } from "react";
import { useQuery } from '@tanstack/react-query';
import { getMedicalRecords } from '@/actions/medical-records';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { format } from "date-fns";
import { Loader2, FileText, ChevronDown, ChevronRight } from "lucide-react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Button } from "@/components/ui/button";

interface MedicalHistoryTabProps {
    patientId: string;
}

export function MedicalHistoryTab({ patientId }: MedicalHistoryTabProps) {
    const { data: records = [], isLoading } = useQuery({
        queryKey: ['medical-records', patientId],
        queryFn: () => getMedicalRecords(patientId)
    });

    if (isLoading) {
        return (
            <div className="flex justify-center p-8">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        );
    }

    if (records.length === 0) {
        return (
            <CardContent className="flex flex-col items-center justify-center p-8 text-center text-muted-foreground">
                <FileText className="h-12 w-12 mb-4 opacity-50" />
                <p>Nenhum prontuário registrado para este paciente.</p>
            </CardContent>
        );
    }

    return (
        <ScrollArea className="h-full pr-4">
            <div className="space-y-4">
                {records.map((record) => (
                    <RecordCard key={record.id} record={record} />
                ))}
            </div>
        </ScrollArea>
    );
}

function RecordCard({ record }: { record: any }) {
    const [isOpen, setIsOpen] = useState(false);

    return (
        <Collapsible open={isOpen} onOpenChange={setIsOpen} className="border rounded-md bg-card">
            <div className="flex items-center justify-between p-4">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="sm" className="p-0 h-auto hover:bg-transparent" onClick={() => setIsOpen(!isOpen)}>
                        {isOpen ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
                    </Button>
                    <div>
                        <h4 className="font-semibold">{format(new Date(record.created_at), 'dd/MM/yyyy HH:mm')}</h4>
                        <span className="text-sm text-muted-foreground">{record.doctor?.full_name}</span>
                    </div>
                </div>
                <div className="flex gap-2">
                    <Badge>{record.record_type}</Badge>
                </div>
            </div>
            <CollapsibleContent className="p-4 pt-0 border-t">
                <div className="mt-4 space-y-4">
                    {record.chief_complaint && (
                        <div>
                            <span className="font-semibold text-sm">Queixa Principal:</span>
                            <p className="text-sm">{record.chief_complaint}</p>
                        </div>
                    )}
                    {record.diagnostic_hypothesis && (
                        <div>
                            <span className="font-semibold text-sm">Diagnóstico:</span>
                            <p className="text-sm">{record.diagnostic_hypothesis}</p>
                        </div>
                    )}
                    {/* Add more fields */}
                </div>
            </CollapsibleContent>
        </Collapsible>
    )
}
